CREATE DATABASE IF NOT EXISTS kids_story_world CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE kids_story_world;

DROP TABLE IF EXISTS stories;
DROP TABLE IF EXISTS categories;
DROP TABLE IF EXISTS languages;

CREATE TABLE languages (
  id INT AUTO_INCREMENT PRIMARY KEY,
  code VARCHAR(10) NOT NULL UNIQUE,
  name VARCHAR(100) NOT NULL,
  voice_code VARCHAR(20) NOT NULL
);

CREATE TABLE categories (
  id INT AUTO_INCREMENT PRIMARY KEY,
  slug VARCHAR(50) NOT NULL UNIQUE,
  name VARCHAR(100) NOT NULL,
  telugu_name VARCHAR(100) NOT NULL,
  icon VARCHAR(20) NOT NULL
);

CREATE TABLE stories (
  id INT AUTO_INCREMENT PRIMARY KEY,
  title VARCHAR(255) NOT NULL,
  language_code VARCHAR(10) NOT NULL,
  category_slug VARCHAR(50) NOT NULL,
  story_text TEXT NOT NULL,
  age_group VARCHAR(20) DEFAULT '4-10',
  reading_time VARCHAR(20) DEFAULT '3 min',
  image_url VARCHAR(500),
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY (language_code) REFERENCES languages(code),
  FOREIGN KEY (category_slug) REFERENCES categories(slug)
);



