INSERT INTO stories (title, language_code, category_slug, story_text, age_group, reading_time, image_url) VALUES
('Moral Stories 1', 'en', 'moral', 'Once there was a kind child named Chinni. One day Chinni found a purse near a mango tree. Instead of keeping it, Chinni gave it to the village teacher. Everyone praised Chinni for honesty. From that day, all children learned that truth gives real happiness.', '4-10', '3 min', 'https://placehold.co/700x430/FFE7A0/333333?text=🌟+Moral+Stories'),
('Moral Stories 2', 'en', 'moral', 'Once there was a kind child named Chinni. One day Chinni found a purse near a mango tree. Instead of keeping it, Chinni gave it to the village teacher. Everyone praised Chinni for honesty. From that day, all children learned that truth gives real happiness.', '4-10', '4 min', 'https://placehold.co/700x430/FFE7A0/333333?text=🌟+Moral+Stories'),
('Moral Stories 3', 'en', 'moral', 'Once there was a kind child named Chinni. One day Chinni found a purse near a mango tree. Instead of keeping it, Chinni gave it to the village teacher. Everyone praised Chinni for honesty. From that day, all children learned that truth gives real happiness.', '4-10', '2 min', 'https://placehold.co/700x430/FFE7A0/333333?text=🌟+Moral+Stories'),
('నీతి కథలు 1', 'te', 'moral', 'ఒక చిన్న గ్రామంలో చిన్నీ అనే మంచి పిల్లాడు ఉండేవాడు. ఒక రోజు మామిడి చెట్టు దగ్గర ఒక పర్స్ కనిపించింది. దాన్ని తన దగ్గర పెట్టుకోకుండా గురువుగారికి ఇచ్చాడు. అందరూ చిన్నీ నిజాయితీని మెచ్చుకున్నారు. నిజం చెప్పడం వల్ల మనసుకు నిజమైన సంతోషం వస్తుందని పిల్లలు నేర్చుకున్నారు.', '4-10', '3 min', 'https://placehold.co/700x430/FFE7A0/333333?text=🌟+Moral+Stories'),
('నీతి కథలు 2', 'te', 'moral', 'ఒక చిన్న గ్రామంలో చిన్నీ అనే మంచి పిల్లాడు ఉండేవాడు. ఒక రోజు మామిడి చెట్టు దగ్గర ఒక పర్స్ కనిపించింది. దాన్ని తన దగ్గర పెట్టుకోకుండా గురువుగారికి ఇచ్చాడు. అందరూ చిన్నీ నిజాయితీని మెచ్చుకున్నారు. నిజం చెప్పడం వల్ల మనసుకు నిజమైన సంతోషం వస్తుందని పిల్లలు నేర్చుకున్నారు.', '4-10', '4 min', 'https://placehold.co/700x430/FFE7A0/333333?text=🌟+Moral+Stories'),
